using LEGAL.Scadenze.Api.Repositories;using LEGAL.Scadenze.Api.Services;using LEGAL.Shared.Helpers;using Serilog;
EnvLoader.Load();Log.Logger=new LoggerConfiguration().MinimumLevel.Information().MinimumLevel.Override("Microsoft",Serilog.Events.LogEventLevel.Warning).WriteTo.Console().WriteTo.File("logs/scadenze-.log",rollingInterval:RollingInterval.Day,retainedFileCountLimit:30).CreateLogger();
try{Log.Information("LEGAL Scadenze starting on port 5224...");var b=WebApplication.CreateBuilder(args);b.Host.UseSerilog();var cs=b.Configuration.GetValue<string>("Database:ConnectionString")??"Data Source=data/scadenze.db";var repo=new ScadenzeRepository(cs);b.Services.AddSingleton(repo);b.Services.AddScoped<IScadenzeService,ScadenzeService>();b.Services.AddControllers();b.Services.AddEndpointsApiExplorer();b.Services.AddSwaggerGen(c=>{c.SwaggerDoc("v1",new(){Title="LEGAL Scadenze",Version="v1"});});b.Services.AddHealthChecks();b.Services.AddCors(o=>o.AddDefaultPolicy(p=>p.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader()));var app=b.Build();await repo.InitializeAsync();app.UseSerilogRequestLogging();app.UseCors();if(app.Environment.IsDevelopment()){app.UseSwagger();app.UseSwaggerUI();}app.MapControllers();app.MapHealthChecks("/api/health");app.Run();}catch(Exception ex){Log.Fatal(ex,"LEGAL Scadenze terminated");}finally{Log.CloseAndFlush();}
